                // Ensure the entry path is within the target directory
                if (!entryPath.startsWith(targetDir)) {
                    throw new IOException("Security violation: Entry '" + entry.getName() + "' resolves outside target directory");
                }

                if (entry.isDirectory()) {
                    // Create directory if it doesn't exist
                    if (!Files.exists(entryPath)) {
                        Files.createDirectories(entryPath);
                    }
                } else {
                    // Ensure parent directories exist
                    Path parentDir = entryPath.getParent();
                    if (!Files.exists(parentDir)) {
                        Files.createDirectories(parentDir);
                    }

                    // Extract the file
                    try (InputStream inputStream = zip.getInputStream(entry)) {
                        Files.copy(inputStream, entryPath, StandardCopyOption.REPLACE_EXISTING);
                    }

                    // Add the absolute path to the result list
                    extractedFiles.add(entryPath.toAbsolutePath().toString());
                }
            }
        } catch (java.util.zip.ZipException e) {
            throw new IOException("Invalid or corrupted ZIP file: " + zipFilePath, e);
        }

        return extractedFiles;
    }
}
